package server
import "net/http"
func (s *Server) dashboard(w http.ResponseWriter, r *http.Request) { w.Header().Set("Content-Type", "text/html"); w.Write([]byte(dashHTML)) }
const dashHTML = `<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Scribe</title><link href="https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;700&display=swap" rel="stylesheet"><style>:root{--bg:#1a1410;--bg2:#241e18;--bg3:#2e261e;--rust:#e8753a;--leather:#a0845c;--cream:#f0e6d3;--cd:#bfb5a3;--cm:#7a7060;--gold:#d4a843;--green:#4a9e5c;--red:#c94444;--blue:#5b8dd9;--mono:'JetBrains Mono',monospace}*{margin:0;padding:0;box-sizing:border-box}body{background:var(--bg);color:var(--cream);font-family:var(--mono);line-height:1.5}.hdr{padding:1rem 1.5rem;border-bottom:1px solid var(--bg3);display:flex;justify-content:space-between;align-items:center}.hdr h1{font-size:.9rem;letter-spacing:2px}.hdr h1 span{color:var(--rust)}.main{padding:1.5rem;max-width:960px;margin:0 auto}.stats{display:grid;grid-template-columns:repeat(3,1fr);gap:.5rem;margin-bottom:1rem}.st{background:var(--bg2);border:1px solid var(--bg3);padding:.6rem;text-align:center}.st-v{font-size:1.2rem;font-weight:700}.st-l{font-size:.5rem;color:var(--cm);text-transform:uppercase;letter-spacing:1px;margin-top:.15rem}.toolbar{display:flex;gap:.5rem;margin-bottom:1rem}.search{flex:1;padding:.4rem .6rem;background:var(--bg2);border:1px solid var(--bg3);color:var(--cream);font-family:var(--mono);font-size:.7rem}.search:focus{outline:none;border-color:var(--leather)}.rec{background:var(--bg2);border:1px solid var(--bg3);padding:.8rem 1rem;margin-bottom:.5rem;transition:border-color .2s}.rec:hover{border-color:var(--leather)}.rec-top{display:flex;justify-content:space-between;align-items:flex-start;gap:.5rem}.rec-title{font-size:.85rem;font-weight:700}.rec-summary{font-size:.7rem;color:var(--cd);margin-top:.2rem;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden}.rec-meta{font-size:.55rem;color:var(--cm);margin-top:.3rem;display:flex;gap:.5rem;flex-wrap:wrap;align-items:center}.rec-actions{display:flex;gap:.3rem;flex-shrink:0}.badge{font-size:.5rem;padding:.12rem .35rem;text-transform:uppercase;letter-spacing:1px;border:1px solid}.badge.pending{border-color:var(--gold);color:var(--gold)}.badge.transcribed{border-color:var(--green);color:var(--green)}.badge.processing{border-color:var(--blue);color:var(--blue)}.tag{font-size:.45rem;padding:.1rem .25rem;background:var(--bg3);color:var(--cm)}.btn{font-size:.6rem;padding:.25rem .5rem;cursor:pointer;border:1px solid var(--bg3);background:var(--bg);color:var(--cd);transition:all .2s}.btn:hover{border-color:var(--leather);color:var(--cream)}.btn-p{background:var(--rust);border-color:var(--rust);color:#fff}.btn-sm{font-size:.55rem;padding:.2rem .4rem}.modal-bg{display:none;position:fixed;inset:0;background:rgba(0,0,0,.65);z-index:100;align-items:center;justify-content:center}.modal-bg.open{display:flex}.modal{background:var(--bg2);border:1px solid var(--bg3);padding:1.5rem;width:500px;max-width:92vw;max-height:90vh;overflow-y:auto}.modal h2{font-size:.8rem;margin-bottom:1rem;color:var(--rust)}.fr{margin-bottom:.6rem}.fr label{display:block;font-size:.55rem;color:var(--cm);text-transform:uppercase;letter-spacing:1px;margin-bottom:.2rem}.fr input,.fr select,.fr textarea{width:100%;padding:.4rem .5rem;background:var(--bg);border:1px solid var(--bg3);color:var(--cream);font-family:var(--mono);font-size:.7rem}.fr input:focus,.fr select:focus,.fr textarea:focus{outline:none;border-color:var(--leather)}.row2{display:grid;grid-template-columns:1fr 1fr;gap:.5rem}.acts{display:flex;gap:.4rem;justify-content:flex-end;margin-top:1rem}.empty{text-align:center;padding:3rem;color:var(--cm);font-style:italic;font-size:.75rem}</style></head><body>
<div class="hdr"><h1><span>&#9670;</span> SCRIBE</h1><button class="btn btn-p" onclick="openForm()">+ Add Recording</button></div>
<div class="main"><div class="stats" id="stats"></div><div class="toolbar"><input class="search" id="search" placeholder="Search recordings..." oninput="render()"></div><div id="list"></div></div>
<div class="modal-bg" id="mbg" onclick="if(event.target===this)closeModal()"><div class="modal" id="mdl"></div></div>
<script>
var A='/api',items=[],editId=null;
async function load(){var r=await fetch(A+'/recordings').then(function(r){return r.json()});items=r.recordings||[];renderStats();render();}
function renderStats(){var t=items.length,words=items.reduce(function(s,r){return s+(r.word_count||0)},0),transcribed=items.filter(function(r){return r.status==='transcribed'}).length;
document.getElementById('stats').innerHTML='<div class="st"><div class="st-v">'+t+'</div><div class="st-l">Recordings</div></div><div class="st"><div class="st-v" style="color:var(--green)">'+transcribed+'</div><div class="st-l">Transcribed</div></div><div class="st"><div class="st-v">'+words.toLocaleString()+'</div><div class="st-l">Words</div></div>';}
function render(){var q=(document.getElementById('search').value||'').toLowerCase();var f=items;
if(q)f=f.filter(function(r){return(r.title||'').toLowerCase().includes(q)||(r.summary||'').toLowerCase().includes(q)||(r.tags||'').toLowerCase().includes(q)});
if(!f.length){document.getElementById('list').innerHTML='<div class="empty">No recordings.</div>';return;}
var h='';f.forEach(function(r){
h+='<div class="rec"><div class="rec-top"><div style="flex:1"><div class="rec-title">'+esc(r.title)+'</div>';
if(r.summary)h+='<div class="rec-summary">'+esc(r.summary)+'</div>';
h+='</div><div class="rec-actions"><button class="btn btn-sm" onclick="openEdit(''+r.id+'')">Edit</button><button class="btn btn-sm" onclick="del(''+r.id+'')" style="color:var(--red)">&#10005;</button></div></div>';
h+='<div class="rec-meta">';
if(r.status)h+='<span class="badge '+r.status+'">'+r.status+'</span>';
if(r.source)h+='<span>'+esc(r.source)+'</span>';
if(r.duration)h+='<span>'+esc(r.duration)+'</span>';
if(r.word_count)h+='<span>'+r.word_count+' words</span>';
if(r.tags){r.tags.split(',').forEach(function(t){t=t.trim();if(t)h+='<span class="tag">#'+esc(t)+'</span>';});}
h+='<span>'+ft(r.created_at)+'</span></div></div>';});
document.getElementById('list').innerHTML=h;}
async function del(id){if(!confirm('Delete?'))return;await fetch(A+'/recordings/'+id,{method:'DELETE'});load();}
function formHTML(rec){var i=rec||{title:'',source:'',duration:'',transcript:'',summary:'',tags:'',status:'pending'};var isEdit=!!rec;
var h='<h2>'+(isEdit?'EDIT':'ADD')+' RECORDING</h2>';
h+='<div class="fr"><label>Title *</label><input id="f-title" value="'+esc(i.title)+'"></div>';
h+='<div class="row2"><div class="fr"><label>Source</label><input id="f-source" value="'+esc(i.source)+'" placeholder="e.g. meeting, podcast"></div><div class="fr"><label>Duration</label><input id="f-dur" value="'+esc(i.duration)+'" placeholder="e.g. 45:30"></div></div>';
h+='<div class="fr"><label>Transcript</label><textarea id="f-trans" rows="4">'+esc(i.transcript)+'</textarea></div>';
h+='<div class="fr"><label>Summary</label><textarea id="f-sum" rows="2">'+esc(i.summary)+'</textarea></div>';
h+='<div class="row2"><div class="fr"><label>Status</label><select id="f-status"><option value="pending"'+(i.status==='pending'?' selected':'')+'>Pending</option><option value="processing"'+(i.status==='processing'?' selected':'')+'>Processing</option><option value="transcribed"'+(i.status==='transcribed'?' selected':'')+'>Transcribed</option></select></div><div class="fr"><label>Tags</label><input id="f-tags" value="'+esc(i.tags)+'" placeholder="comma separated"></div></div>';
h+='<div class="acts"><button class="btn" onclick="closeModal()">Cancel</button><button class="btn btn-p" onclick="submit()">'+(isEdit?'Save':'Add')+'</button></div>';return h;}
function openForm(){editId=null;document.getElementById('mdl').innerHTML=formHTML();document.getElementById('mbg').classList.add('open');}
function openEdit(id){var r=null;for(var j=0;j<items.length;j++){if(items[j].id===id){r=items[j];break;}}if(!r)return;editId=id;document.getElementById('mdl').innerHTML=formHTML(r);document.getElementById('mbg').classList.add('open');}
function closeModal(){document.getElementById('mbg').classList.remove('open');editId=null;}
async function submit(){var title=document.getElementById('f-title').value.trim();if(!title){alert('Title required');return;}
var body={title:title,source:document.getElementById('f-source').value.trim(),duration:document.getElementById('f-dur').value.trim(),transcript:document.getElementById('f-trans').value.trim(),summary:document.getElementById('f-sum').value.trim(),status:document.getElementById('f-status').value,tags:document.getElementById('f-tags').value.trim()};
if(editId){await fetch(A+'/recordings/'+editId,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)});}
else{await fetch(A+'/recordings',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)});}closeModal();load();}
function ft(t){if(!t)return'';try{return new Date(t).toLocaleDateString('en-US',{month:'short',day:'numeric'})}catch(e){return t;}}
function esc(s){if(!s)return'';var d=document.createElement('div');d.textContent=s;return d.innerHTML;}
document.addEventListener('keydown',function(e){if(e.key==='Escape')closeModal();});load();
</script></body></html>`
